# Idempotent Payment Processing Design

## Core Mechanism: Idempotency Keys

```typescript
interface PaymentRequest {
  idempotencyKey: string;    // Client generates UUID
  amount: number;
  currency: string;
  customerId: string;
  // ... other fields
}

interface ProcessedPayment {
  idempotencyKey: string;
  paymentId: string;
  status: 'pending' | 'succeeded' | 'failed';
  result?: PaymentResult | PaymentError;
  processedAt: timestamp;
}

// Server-side idempotency store (persistent)
class IdempotencyStore {
  async getOrProcess(
    request: PaymentRequest,
    processor: () => Promise<PaymentResult>
  ): Promise<PaymentResult> {
    const key = request.idempotencyKey;

    // 1. Check if already processed
    const existing = await this.store.get(key);
    if (existing) {
      if (existing.status === 'succeeded') {
        return existing.result;
      }
      if (existing.status === 'failed') {
        throw existing.error;
      }
      // Still pending - wait or return status
      throw new PaymentPending(existing.paymentId);
    }

    // 2. Record pending state BEFORE processing
    const paymentId = generateId();
    await this.store.set(key, {
      idempotencyKey: key,
      paymentId,
      status: 'pending',
      createdAt: now(),
    });

    // 3. Process with transactional safety
    try {
      const result = await processor();

      // 4. Record success atomically
      await this.store.set(key, {
        idempotencyKey: key,
        paymentId,
        status: 'succeeded',
        result,
        processedAt: now(),
      });

      return result;
    } catch (error) {
      // 5. Record failure (including network errors)
      await this.store.set(key, {
        idempotencyKey: key,
        paymentId,
        status: 'failed',
        error: error.message,
        processedAt: now(),
      });
      throw error;
    }
  }
}
```

## State Machine for Payment Lifecycle

```typescript
enum PaymentState {
  PENDING = 'pending',           // Initial/retrying
  CONFIRMED = 'confirmed',       // Gateway confirmed (but not settled)
  SETTLED = 'settled',           // Money moved (irreversible)
  FAILED = 'failed',             // Gateway rejected
  CANCELLED = 'cancelled',       // User cancelled before settlement
}

class PaymentStateMachine {
  async processPayment(
    request: PaymentRequest
  ): Promise<Payment> {
    const idempotencyKey = request.idempotencyKey;

    // Use database transaction for atomic writes
    return db.transaction(async (tx) => {
      // Ensure only one writer per idempotency key
      const lockKey = `payment:${idempotencyKey}`;
      await tx.acquireLock(lockKey, { timeout: 30000 });

      // Check existing payment
      let payment = await tx.findPayment(idempotencyKey);

      if (payment) {
        // Idempotent return
        return this.handleExistingPayment(payment);
      }

      // Create new payment record
      payment = await tx.insert('payments', {
        idempotencyKey,
        paymentId: generateId(),
        customerId: request.customerId,
        amount: request.amount,
        currency: request.currency,
        state: PaymentState.PENDING,
        createdAt: now(),
        attempts: 0,
      });

      return payment;
    });
  }

  private async handleExistingPayment(
    payment: Payment
  ): Promise<Payment> {
    switch (payment.state) {
      case PaymentState.SETTLED:
        return payment; // Success - return stored result

      case PaymentState.CONFIRMED:
        return payment; // Safe to return (settlement is automatic)

      case PaymentState.PENDING:
        // Check if we should retry or return pending
        if (this.shouldRetry(payment)) {
          return this.retryPayment(payment);
        }
        throw new PaymentPending(payment.paymentId);

      case PaymentState.FAILED:
        throw new PaymentFailed(payment.paymentId);

      default:
        throw new InvalidPaymentState(payment.state);
    }
  }
}
```

## Gateway Integration with Webhook Verification

```typescript
class PaymentGateway {
  async chargeWithRetry(payment: Payment): Promise<GatewayResponse> {
    const maxRetries = 3;
    let lastError: Error | null = null;

    for (let attempt = 0; attempt < maxRetries; attempt++) {
      try {
        // Critical: Send idempotency key to gateway too
        const response = await this.gateway.charge({
          idempotencyKey: payment.idempotencyKey,
          amount: payment.amount,
          customerId: payment.customerId,
          // Gateway also de-dupes on their side
        });

        // Don't update payment state here - wait for webhook
        return response;

      } catch (error) {
        lastError = error;

        // Retry only on network errors, NOT on business logic errors
        if (!this.isRetryable(error)) {
          await this.recordFailure(payment, error);
          throw error;
        }

        // Exponential backoff
        if (attempt < maxRetries - 1) {
          await sleep(Math.pow(2, attempt) * 1000);
        }
      }
    }

    throw lastError;
  }

  private isRetryable(error: Error): boolean {
    // Retry on network/timeout errors
    return error instanceof NetworkError ||
           error instanceof TimeoutError ||
           error.code === 'GATEWAY_TIMEOUT';
  }
}

// Webhook handler - THIS updates payment state
class WebhookHandler {
  async handleGatewayEvent(event: GatewayEvent) {
    const { idempotencyKey, status, transactionId } = event;

    return db.transaction(async (tx) => {
      const payment = await tx.findPayment(idempotencyKey);

      if (!payment) {
        // Webhook before we recorded initial request - queue for retry
        await this.retryQueue.enqueue(() => 
          this.handleGatewayEvent(event), 
          { delayMs: 5000, maxRetries: 10 }
        );
        return;
      }

      // Verify webhook signature before processing
      if (!this.verifyWebhookSignature(event)) {
        throw new WebhookVerificationFailed();
      }

      // Update payment state based on gateway response
      if (status === 'succeeded') {
        await tx.update('payments', payment.id, {
          state: PaymentState.SETTLED,
          transactionId,
          settledAt: now(),
        });
      } else if (status === 'failed') {
        await tx.update('payments', payment.id, {
          state: PaymentState.FAILED,
          failureReason: event.failureReason,
          failedAt: now(),
        });
      }
    });
  }
}
```

## Client-Side Implementation

```typescript
class PaymentClient {
  async submitPayment(request: PaymentRequest): Promise<PaymentResult> {
    // Generate idempotency key once, reuse on retries
    const idempotencyKey = request.idempotencyKey || generateUUID();

    const maxRetries = 5;
    let lastError: Error | null = null;

    for (let attempt = 0; attempt < maxRetries; attempt++) {
      try {
        const response = await fetch('/api/payments', {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'Idempotency-Key': idempotencyKey,
          },
          body: JSON.stringify({
            ...request,
            idempotencyKey,
          }),
        });

        if (response.ok) {
          return response.json();
        }

        // 409 Conflict = already processing
        if (response.status === 409) {
          // Poll for status with backoff
          return this.pollPaymentStatus(idempotencyKey);
        }

        // 4xx errors are not retryable
        if (response.status >= 400 && response.status < 500) {
          throw new ClientError(response.status, response.statusText);
        }

        lastError = new Error(`HTTP ${response.status}`);

      } catch (error) {
        lastError = error;
        // Network error - retry with backoff
      }

      // Exponential backoff with jitter
      if (attempt < maxRetries - 1) {
        const delay = Math.pow(2, attempt) * 1000 + Math.random() * 1000;
        await sleep(delay);
      }
    }

    throw new PaymentProcessingFailed(lastError, idempotencyKey);
  }

  private async pollPaymentStatus(idempotencyKey: string) {
    const maxPolls = 30;
    for (let i = 0; i < maxPolls; i++) {
      const response = await fetch(
        `/api/payments/status?idempotencyKey=${idempotencyKey}`
      );
      const payment = await response.json();

      if (payment.state === 'settled') {
        return payment;
      }
      if (payment.state === 'failed') {
        throw new PaymentFailed(payment);
      }

      // Still pending - wait
      await sleep(1000 + i * 500); // Increasing backoff
    }

    throw new PaymentStatusTimeout(idempotencyKey);
  }
}
```

## Key Design Principles

| Aspect | Solution |
|--------|----------|
| **Deduplication** | Idempotency keys stored in persistent DB, checked before processing |
| **Atomic Recording** | Record pending state BEFORE calling gateway; update on webhook |
| **Network Resilience** | Retryable errors get exponential backoff; non-retryable fail immediately |
| **State Machine** | Payment state clearly tracks: pending → confirmed → settled (irreversible point) |
| **Webhook Safety** | Webhook handler is the source of truth; retries on queue if payment not yet recorded |
| **Idempotency at Layers** | Client uses UUID; server dedupes; gateway dedupes (mutual idempotency) |
| **Locking** | Distributed lock on idempotency key prevents concurrent processing |

## Storage Requirements

```sql
CREATE TABLE payments (
  id UUID PRIMARY KEY,
  idempotencyKey VARCHAR(255) UNIQUE NOT NULL,
  paymentId VARCHAR(255) UNIQUE NOT NULL,
  customerId VARCHAR(255) NOT NULL,
  amount DECIMAL(19,4) NOT NULL,
  currency VARCHAR(3) NOT NULL,
  state VARCHAR(50) NOT NULL,  -- pending|confirmed|settled|failed
  transactionId VARCHAR(255),   -- from gateway
  failureReason TEXT,
  createdAt TIMESTAMP NOT NULL,
  settledAt TIMESTAMP,
  failedAt TIMESTAMP,
  INDEX (idempotencyKey),
  INDEX (customerId, createdAt)
);

CREATE TABLE idempotency_results (
  key VARCHAR(255) PRIMARY KEY,
  status VARCHAR(50) NOT NULL,
  result JSONB,
  error JSONB,
  createdAt TIMESTAMP NOT NULL,
  expiresAt TIMESTAMP NOT NULL  -- TTL for cleanup
);
```

This design ensures exactly-once payment processing despite retries, network partitions, and concurrent requests.

# React Search List Re-render Diagnosis

## The Problem

Every keystroke triggers a full list re-render because the search input state lives in the same component as the list. Each state update causes the parent to re-render all children.

---

## Solutions with Tradeoff Analysis

### **Option A: Separate Concerns (Recommended for most cases)**

```jsx
// ❌ SLOW - Everything re-renders
function SearchableList() {
  const [search, setSearch] = useState('');
  const items = ['Apple', 'Banana', 'Avocado'];
  const filtered = items.filter(item => 
    item.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <>
      <input value={search} onChange={e => setSearch(e.target.value)} />
      <List items={filtered} />
    </>
  );
}

// ✅ FAST - Only input re-renders
function SearchableList() {
  const [search, setSearch] = useState('');
  const items = ['Apple', 'Banana', 'Avocado'];
  const filtered = items.filter(item => 
    item.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <>
      <SearchInput value={search} onChange={setSearch} />
      <List items={filtered} />
    </>
  );
}

function SearchInput({ value, onChange }) {
  return <input value={value} onChange={e => onChange(e.target.value)} />;
}
```

**Tradeoff**: 
- ✅ Cleanest fix, minimal overhead
- ❌ Requires component restructuring
- ✅ Better long-term maintainability

---

### **Option B: useMemo (Quickest fix)**

```jsx
function SearchableList() {
  const [search, setSearch] = useState('');
  const items = ['Apple', 'Banana', 'Avocado'];

  const filtered = useMemo(() => 
    items.filter(item => 
      item.toLowerCase().includes(search.toLowerCase())
    ),
    [search, items] // Only recalculate when these change
  );

  return (
    <>
      <input value={search} onChange={e => setSearch(e.target.value)} />
      <List items={filtered} />
    </>
  );
}
```

**Tradeoff**:
- ✅ One-line fix, works immediately
- ✅ Memoization prevents redundant calculations
- ❌ Doesn't prevent List component re-render (still re-render, just faster)
- ⚠️ Adds slight memory overhead

---

### **Option C: React.memo + Keys (For item-level optimization)**

```jsx
const ListItem = React.memo(({ item, id }) => (
  <li key={id}>{item}</li>
));

function List({ items }) {
  return (
    <ul>
      {items.map((item, idx) => (
        <ListItem key={item} item={item} id={idx} />
      ))}
    </ul>
  );
}
```

**Tradeoff**:
- ✅ Prevents individual item re-renders if props stable
- ❌ List container still re-renders
- ⚠️ Shallow prop comparison can miss mutations
- ⚠️ Requires stable, unique keys

---

### **Option D: useCallback (Stabilize filter function)**

```jsx
const filterItems = useCallback((items, search) => 
  items.filter(item => 
    item.toLowerCase().includes(search.toLowerCase())
  ),
  [] // Never changes
);

function SearchableList() {
  const [search, setSearch] = useState('');
  const filtered = useMemo(() => 
    filterItems(items, search),
    [search, filterItems]
  );

  return <List items={filtered} />;
}
```

**Tradeoff**:
- ❌ Overkill for simple filters
- ✅ Useful if passing filter to memoized child components
- ⚠️ Adds complexity without proportional benefit here

---

### **Option E: Debounce (UX tradeoff)**

```jsx
function SearchableList() {
  const [search, setSearch] = useState('');
  const [debouncedSearch, setDebouncedSearch] = useState('');

  useEffect(() => {
    const timer = setTimeout(() => setDebouncedSearch(search), 300);
    return () => clearTimeout(timer);
  }, [search]);

  const filtered = items.filter(item =>
    item.toLowerCase().includes(debouncedSearch.toLowerCase())
  );

  return (
    <>
      <input value={search} onChange={e => setSearch(e.target.value)} />
      <List items={filtered} />
    </>
  );
}
```

**Tradeoff**:
- ✅ Dramatically reduces filter calculations
- ❌ List doesn't update while typing (300ms lag)
- ⚠️ Poor UX for small lists, good for huge datasets
- ✅ Best combined with Options A or B

---

## Quick Decision Tree

| Scenario | Best Fix |
|----------|----------|
