);

CREATE TABLE flag_rules (
  id UUID PRIMARY KEY,
  flag_id UUID REFERENCES flags(id) ON DELETE CASCADE,
  priority INT,
  condition_type VARCHAR(50),
  condition_value JSON,
  rollout_percentage INT,
  created_at TIMESTAMP,

  INDEX(flag_id, priority DESC)
);

CREATE TABLE flag_evaluations (
  id UUID PRIMARY KEY,
  flag_name VARCHAR(255),
  user_id VARCHAR(255),
  timestamp TIMESTAMP,
  client_result BOOLEAN,
  server_result BOOLEAN,
  mismatch BOOLEAN,

  INDEX(flag_name),
  INDEX(timestamp),
  INDEX(mismatch)  -- Alert on mismatches
);
